sysauto_script.script:
(function() {
    // Find blood inventory records that have expired
    var today = new GlideDateTime().getDate().getValue();

    var gr = new GlideRecord('x_1920732_lifeli_0_blood_inventory');
    gr.addQuery('expiry_date', '<', today);
    gr.addQuery('units_available', '>', 0);
    gr.query();

    var count = 0;
    while (gr.next()) {
        var previousUnits = gr.getValue('units_available');

        // Mark inventory as expired (set units to 0)
        gr.setValue('units_available', 0);
        gr.setValue('last_updated', new GlideDateTime().getValue());
        gr.update();

        // Fire low stock event if applicable
        gs.eventQueue('x_1920732_lifeli_0.inv.low_stock', gr, gr.getValue('blood_bank'), gr.getValue('blood_group'));

        count++;
        gs.info('LifeLink: Expired inventory detected - Blood Bank: ' + gr.getDisplayValue('blood_bank') + ', Blood Group: ' + gr.getValue('blood_group') + ', Expired Units: ' + previousUnits);
    }
    gs.info('LifeLink: Expired Inventory Checker processed ' + count + ' expired records.');
})();
